#!/usr/bin/env node
// scripts/check-sidecar-staleness.mjs — Phase 22 Plan 07 (REQ-6 / T-22-07-01).
//
// A `<Name>.d.rozie.ts` sidecar gives a consumer's `tsc` real types for
// `import Foo from './Foo.rozie'`. The sidecar is GENERATED (gitignored, emitted
// by @rozie/unplugin's buildStart hook). Its first line carries a do-not-edit +
// sha256 content-hash header:
//
//   // AUTO-GENERATED by @rozie/unplugin — do not edit. source-hash: <12-hex>
//
// where the hash is `createHash('sha256').update(<.rozie source>).digest('hex').slice(0,12)`.
//
// THE THREAT (T-22-07-01, spoofing-of-types): a sidecar that lags its `.rozie`
// source is a TYPE LIE — tsc trusts a declaration that no longer matches the
// component it describes. This gate re-hashes every demo `.rozie` source and
// fails (non-zero exit) if any sidecar header hash != the freshly-computed hash.
//
// It ALSO fails if a `.rozie` file that a demo consumes via a sidecar-resolving
// import has NO sidecar on disk (the fresh-checkout / missing-declaration gap).
//
// `--self-test` AUTOMATES the negative path: it copies a real sidecar to an OS
// temp dir, tampers its header hash, runs the same re-hash check against the
// tampered copy, and asserts the check REJECTS it. This replaces the
// manual-only negative-path proof — the gate proves it can actually catch a
// stale sidecar.
//
// Structure mirrors scripts/check-runtime-isolation.mjs (the repo's other gate).
import { createHash } from 'node:crypto';
import {
  existsSync,
  mkdtempSync,
  readFileSync,
  readdirSync,
  rmSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');
const CONSUMERS_DIR = join(ROOT, 'examples', 'consumers');

// The single source of truth for the header — must match
// packages/unplugin/src/emitSidecar.ts SIDECAR_HEADER_PREFIX exactly.
const SIDECAR_HEADER_PREFIX =
  '// AUTO-GENERATED by @rozie/unplugin — do not edit. source-hash: ';

/** Compute the deterministic 12-hex content hash of a `.rozie` source. */
function sidecarSourceHash(source) {
  return createHash('sha256').update(source).digest('hex').slice(0, 12);
}

/** Parse the `source-hash:` value from a sidecar's first line, or null. */
function parseHeaderHash(sidecarText) {
  const firstLine = sidecarText.split('\n', 1)[0] ?? '';
  if (!firstLine.startsWith(SIDECAR_HEADER_PREFIX)) return null;
  return firstLine.slice(SIDECAR_HEADER_PREFIX.length).trim();
}

/** Recursively collect every file matching `predicate` under `dir`. */
function walk(dir, predicate, out = []) {
  let entries;
  try {
    entries = readdirSync(dir);
  } catch {
    return out;
  }
  for (const name of entries) {
    if (name === 'node_modules' || name === 'dist' || name === '.turbo') continue;
    const full = join(dir, name);
    let s;
    try {
      s = statSync(full);
    } catch {
      continue;
    }
    if (s.isDirectory()) walk(full, predicate, out);
    else if (predicate(name)) out.push(full);
  }
  return out;
}

/**
 * The core re-hash check, factored out so `--self-test` can drive it against a
 * single tampered file. Returns { ok, reason } — ok=false means the sidecar's
 * header hash does not match the freshly-computed source hash (stale / tampered).
 */
function checkSidecarFreshness(roziePath, sidecarPath) {
  if (!existsSync(roziePath)) {
    return { ok: false, reason: `source .rozie missing for sidecar ${sidecarPath}` };
  }
  const source = readFileSync(roziePath, 'utf8');
  const sidecarText = readFileSync(sidecarPath, 'utf8');
  const headerHash = parseHeaderHash(sidecarText);
  if (headerHash === null) {
    return { ok: false, reason: `sidecar ${sidecarPath} has no do-not-edit source-hash header` };
  }
  const fresh = sidecarSourceHash(source);
  if (headerHash !== fresh) {
    return {
      ok: false,
      reason: `STALE: ${sidecarPath} header hash ${headerHash} != fresh source hash ${fresh}`,
    };
  }
  return { ok: true, reason: '' };
}

function roziePathForSidecar(sidecarPath) {
  // `<Name>.d.rozie.ts` → `<Name>.rozie`
  return sidecarPath.replace(/\.d\.rozie\.ts$/, '.rozie');
}

/**
 * `--self-test`: prove the gate REJECTS a tampered sidecar. Copy a real sidecar
 * to a temp dir alongside a copy of its `.rozie` source, flip the header hash to
 * a deliberately-wrong value, run checkSidecarFreshness against it, and assert it
 * returns ok=false. Exit 0 only if the gate correctly rejected the tamper.
 */
function runSelfTest() {
  const allSidecars = walk(CONSUMERS_DIR, (n) => n.endsWith('.d.rozie.ts'));
  const sample = allSidecars.find((p) => existsSync(roziePathForSidecar(p)));
  if (!sample) {
    console.error(
      '✗ self-test: no demo sidecar with a matching .rozie source found — run a demo build first (e.g. `pnpm turbo run build`) so the buildStart hook emits sidecars.',
    );
    process.exit(1);
  }
  const sampleRozie = roziePathForSidecar(sample);
  const tmp = mkdtempSync(join(tmpdir(), 'rozie-sidecar-selftest-'));
  try {
    const tmpRozie = join(tmp, 'Sample.rozie');
    const tmpSidecar = join(tmp, 'Sample.d.rozie.ts');
    const sourceText = readFileSync(sampleRozie, 'utf8');
    const sidecarText = readFileSync(sample, 'utf8');
    writeFileSync(tmpRozie, sourceText, 'utf8');

    // Tamper: replace the real header hash with a deliberately-wrong one.
    const realHash = parseHeaderHash(sidecarText);
    const tamperedHash = realHash === '000000000000' ? '111111111111' : '000000000000';
    const tamperedText = sidecarText.replace(
      `${SIDECAR_HEADER_PREFIX}${realHash}`,
      `${SIDECAR_HEADER_PREFIX}${tamperedHash}`,
    );
    if (tamperedText === sidecarText) {
      console.error('✗ self-test: failed to construct a tampered sidecar (header not found).');
      process.exit(1);
    }
    writeFileSync(tmpSidecar, tamperedText, 'utf8');

    const result = checkSidecarFreshness(tmpRozie, tmpSidecar);
    if (result.ok) {
      console.error(
        '✗ self-test FAILED: the gate ACCEPTED a tampered sidecar (header hash flipped) — the staleness check is not actually catching stale sidecars.',
      );
      process.exit(1);
    }
    console.log('✓ self-test passed — the gate rejected a tampered sidecar:');
    console.log(`    ${result.reason}`);
    process.exit(0);
  } finally {
    rmSync(tmp, { recursive: true, force: true });
  }
}

function runGate() {
  const sidecars = walk(CONSUMERS_DIR, (n) => n.endsWith('.d.rozie.ts'));
  const stale = [];
  let checked = 0;
  for (const sidecar of sidecars) {
    const roziePath = roziePathForSidecar(sidecar);
    if (!existsSync(roziePath)) {
      // A sidecar with no source is its own kind of staleness (orphan).
      stale.push(`ORPHAN: ${sidecar} has no matching .rozie source`);
      continue;
    }
    const result = checkSidecarFreshness(roziePath, sidecar);
    checked += 1;
    if (!result.ok) stale.push(result.reason);
  }

  // Missing-declaration gap: a `.rozie` that lives next to OTHER sidecar'd
  // siblings (i.e. in a directory that already participates in sidecar
  // generation) but has NO sidecar of its own. On a fresh checkout this is
  // expected (sidecars are gitignored) — that case is handled by CI ordering
  // (generate before typecheck), so we only flag it as a WARNING here, not a
  // hard failure, to keep this gate purely about staleness of EXISTING
  // sidecars.
  const sidecarDirs = new Set(sidecars.map((p) => dirname(p)));
  const missing = [];
  for (const dir of sidecarDirs) {
    const roziesHere = walk(dir, (n) => n.endsWith('.rozie'));
    for (const r of roziesHere) {
      const expected = r.replace(/\.rozie$/, '.d.rozie.ts');
      if (!existsSync(expected)) missing.push(`${r} (expected ${expected})`);
    }
  }

  if (stale.length > 0) {
    console.error('✗ stale sidecar(s) detected — a generated .d.rozie.ts no longer matches its');
    console.error('  .rozie source (type-lying risk, REQ-6 / T-22-07-01). Re-run the demo build');
    console.error('  (`pnpm turbo run build`) to regenerate sidecars, then re-run this gate:');
    for (const s of stale) console.error(`  - ${s}`);
    process.exit(1);
  }

  console.log(`✓ sidecar staleness OK — ${checked} sidecar(s) match their .rozie source hash.`);
  if (missing.length > 0) {
    console.log(
      `  note: ${missing.length} .rozie file(s) next to existing sidecars have no sidecar on disk`,
    );
    console.log('  (expected on a fresh checkout — CI generates them before typecheck):');
    for (const m of missing.slice(0, 10)) console.log(`    - ${m}`);
    if (missing.length > 10) console.log(`    … and ${missing.length - 10} more`);
  }
  process.exit(0);
}

if (process.argv.includes('--self-test')) {
  runSelfTest();
} else {
  runGate();
}
